    int numSub(string s) {
        int total = 0;
        int current = 0;
        const int MOD = 1000000007;
        for (char c : s) {
            if (c == '1') {
                current++;
            } else {
                total += current * (current + 1) / 2;
                current = 0;
            }
        }
        total += current * (current + 1) / 2;
        return total % MOD;
    }
